{"Configuration":"/** @param {Context} context */
const SetValue = async (context) => {
    // Extract phone numbers safely
    const updatedPhone = context?.Form?.Page1?.UpdatedPrimaryPhoneNumber?.Value || "";
    const primaryPhone = context?.Form?.Page1?.PrimaryPhoneNumber?.Value || "";

    // Function to clean and format phone numbers
    const formatPhoneNumber = (phone) => {
        // Extract only digits
        const digits = phone.replace(/\D/g, "");

        // Ensure it has exactly 10 digits
        if (digits.length !== 10) return phone; // Return as-is if not a valid 10-digit number

        // Format to (000) 000-0000
        return `(${digits.slice(0, 3)}) ${digits.slice(3, 6)}-${digits.slice(6)}`;
    };

    // Determine which phone number to use
    const selectedPhone = updatedPhone !== "" ? updatedPhone : primaryPhone;

    // Return formatted phone number
    return formatPhoneNumber(selectedPhone);
};
