const SetValue = async (context) => {
    // Extract form values
    const sameAsElectric = context?.Form?.EnergyInformationPage?.IsYourNaturalGasCompanyTheSameAsYourElectricCompany?.Value || "";
    const electricUtility = context?.Form?.EnergyInformationPage?.ElectricBillCustomerName?.Value || "";
    const gasUtility = context?.Form?.EnergyInformationPage?.GasBillCustomerName?.Value || "";
    const gasHolder = context?.Form?.EnergyInformationPage?.AreYouTheNaturalGasAccountHolder?.Value || "";
    const accountName = context?.Form?.Page1?.AccountName?.Value || "";

    // Check gas holder first
    if (gasHolder === "Yes") {
        return accountName;
    }

